# launch.ps1 - Self-healing launcher for a Claude Desktop instance
#
# Generated by setup.ps1 for instance: __INSTANCE_NAME__
# user-data-dir: __USER_DATA_DIR__
# shortcut    : __SHORTCUT_PATH__
#
# Why this exists:
#   The desktop shortcut needs to keep working across Claude updates. Claude
#   Desktop installs under C:\Program Files\WindowsApps\Claude_<version>_x64__...
#   and the <version> folder is replaced (not updated in place) on every release.
#   Anything that hardcodes that path - the .lnk TargetPath, the .lnk
#   IconLocation, etc. - breaks the moment Claude updates.
#
# This launcher solves it by re-scanning WindowsApps\Claude_* at every run.
# In addition, it refreshes the calling shortcut's IconLocation to point at
# the current Claude.exe, so the desktop icon never falls back to the generic
# "missing icon" glyph.

$ErrorActionPreference = 'Stop'
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8

$userDataDir  = '__USER_DATA_DIR__'
$instanceName = '__INSTANCE_NAME__'
$shortcutPath = '__SHORTCUT_PATH__'

# --- Find the current Claude.exe ---
$claudeExe = Get-ChildItem 'C:\Program Files\WindowsApps\' -Directory -Filter 'Claude_*' -ErrorAction SilentlyContinue |
    Sort-Object Name -Descending |
    ForEach-Object { Join-Path $_.FullName 'app\Claude.exe' } |
    Where-Object { Test-Path $_ } |
    Select-Object -First 1

if (-not $claudeExe) {
    Write-Host "[X] Claude.exe not found under C:\Program Files\WindowsApps\Claude_*\." -ForegroundColor Red
    Write-Host "    Is Claude Desktop installed? Install it from the Microsoft Store." -ForegroundColor Yellow
    Read-Host "Press Enter to exit"
    exit 1
}

Write-Host "[OK] Launching Claude (instance: $instanceName)" -ForegroundColor Green
Write-Host "     $claudeExe" -ForegroundColor DarkGray

# --- Launch Claude ---
Start-Process -FilePath $claudeExe -ArgumentList "--user-data-dir=`"$userDataDir`""

# --- Refresh shortcut icon so it tracks the current Claude version ---
# Best-effort: don't block launch if this fails for any reason.
if ($shortcutPath -and (Test-Path $shortcutPath)) {
    try {
        $wsh = New-Object -ComObject WScript.Shell
        $sc  = $wsh.CreateShortcut($shortcutPath)
        $expected = "$claudeExe,0"
        if ($sc.IconLocation -ne $expected) {
            $sc.IconLocation = $expected
            $sc.Save()
        }
    } catch {
        # Silent: icon refresh is a nice-to-have, not a launch dependency.
    }
}
